#include <stdio.h>
#include <stdlib.h>

int main(void) {
    int numbers[5], guessPos, guessType, score = 0;
    char guessStr[2];

    // Generate 5 unique random numbers (1-10)
    for (int i = 0; i < 5; i++) {
        do {
            numbers[i] = rand() % 10 + 1;
        } while (i > 0 && numbers[i] == numbers[i - 1]);
    }

    // Hide numbers initially
    for (int i = 0; i < 5; i++) {
        printf("* ");
    }
    printf("\n");

    // Game loop
    for (int i = 0; i < 5; i++) {
        printf("Pick position (1-5): ");
        scanf("%d", &guessPos);
        printf("Guess even or odd (E/O): ");
        scanf("%s", guessStr);

        if (guessPos < 1 || guessPos > 5) {
            printf("Invalid position. Try again.\n");
            continue;
        }

        guessType = (guessStr[0] == 'E') ? 0 : 1;

        if ((numbers[guessPos - 1] % 2 == 0 && guessType == 0) ||
            (numbers[guessPos - 1] % 2 != 0 && guessType == 1)) {
            printf("Correct! You win 5 points.\n");
            score += 5;
        } else {
            printf("Incorrect. The number is %d.\n", numbers[guessPos - 1]);
        }

        // Reveal the number
        printf("Number %d: %d\n", guessPos, numbers[guessPos - 1]);
    }

    // Display final score
    printf("Final score: %d\n", score);

    return 0;
}
